import axios from "axios"
import { useState } from "react"
import { Link } from "react-router-dom"


const LoginPage =()=>{

  const [logData,setLogData] = useState({
    email:'',
    password:''
  })
   const handleSubmit = async(e)=>{
    e.preventDefault()
    try {
      const {data}= await axios.post('/auth/login')
    } catch (error) {
      console.log(error)
    }
   }

   const handleChange =(e)=>{
    setLogData({...logData,[e.target.name]:e.target.value})
   }

    return <div>
      <div>
      <h1 className="mx-auto m-4 w-28">Login PAGE</h1>
      <div>
        <form action="" className="flex justify-center"  onSubmit={handleSubmit}>
          <div className="flex flex-col w-96 ">
            <input type="text" placeholder="EMAIL" name="email" value={logData.email} onChange={handleChange}/>
            <input type="text" placeholder="PASSWORD" name="password" value={logData.password} onChange={handleChange}/>
            <button className="">REGISTER</button>
            <div className="mt-5">
              Already A Member ?{" "}
              <Link to={"/login"} className="text-black font-bold">
                LOGIN
              </Link>
            </div>
          </div>
        </form>
      </div>
    </div>
    </div>
}

export default LoginPage;
